import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第二十章 一壶冷药","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第二十章-一壶冷药.md","filePath":"永恒道途/正文/第一卷-山门有路/第二十章-一壶冷药.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第二十章-一壶冷药.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第二十章-一壶冷药" tabindex="-1">第二十章 一壶冷药 <a class="header-anchor" href="#第二十章-一壶冷药" aria-label="Permalink to &quot;第二十章 一壶冷药&quot;">​</a></h1><p>剑峰在青云七峰最北。</p><p>陈玄寅时前一刻到峰脚，天色仍黑。石阶顺山势没入松林，两侧每隔数十步立一块残旧剑碑。碑上有的只留一线浅痕，有的从中断开，裂口里生着青苔。</p><p>他没有停下参悟。</p><p>李清风只让他寅时上峰，没有说碑林可以随意触碰。何况右腕尚需休养十日，肩脉一个月内不得逆势收剑。此刻盯着旧剑痕强行运气，既不合规矩，也不会因第一日勤奋便多出真正领悟。</p><p>石阶共一千三百级。</p><p>陈玄按昨日下山时估过的脚程走。前四百级稍快，中段保持呼吸，最后三百级每五十级停两息。走到一千一百级，右肋仍开始发紧。</p><p>他没有为了提前更多而加速。</p><p>跨过峰顶石门时，正好寅时。</p><p>剑峰比传闻中简陋。</p><p>三间木屋，一座练剑坪，一口老井，一圈被山风吹歪的竹篱。古松向南倾斜，枝下挂着几只晒干的葫芦。没有成群弟子，也没有灵兽守门。李清风蹲在竹篱边，正拿麻绳把一根裂竹重新捆回去。</p><p>“到了？”</p><p>“弟子陈玄，拜见师父。”</p><p>李清风看了一眼天边，又看他呼吸：“最后两百级用了多久？”</p><p>“比预计多二十息。”</p><p>“为何？”</p><p>“右肋发紧，减速两次。”</p><p>“没有硬赶，算你昨日伤单没白看。”李清风将麻绳咬断，“明日仍这个时辰。若伤重便提早走，不许拿伤换守时。”</p><p>他带陈玄去东屋。</p><p>屋内没有剑架，只有一张矮床、一只青石盆和桌上一壶深褐药汤。药壶外壁已经不冒热气，壶盖边缘凝着一圈水珠。</p><p>陈玄伸手摸了摸。</p><p>凉的。</p><p>“喝。”李清风道。</p><p>药入口先苦，随后舌根发麻，比药堂清创丹更涩。陈玄喝到第三口，右肩旧脉便传出缓慢凉意。</p><p>“寒络草、续脉藤、少量石心乳。”他辨出三味，“这方为何冷服？”</p><p>“石心乳热时沉不下来，会把寒络草药性推得太快。你肩脉是逆势扯伤，不是寒煞，热服会先胀后堵。”</p><p>“药是师父配的？”</p><p>“丹峰开的方。我只负责煎。”</p><p>李清风说得像煎药与扫地无异。陈玄却看见灶边放着三只试药碟，一碟颜色深，一碟有焦边，只有第三碟与壶中相同。</p><p>第一次火大，第二次煎久。</p><p>第三次才成。</p><p>他没有道谢。药只喝了一半便停下：“半壶后右肩开始发凉，指尖无麻。按药堂习惯，应等一刻钟再续。”</p><p>李清风点头：“懂药便自己记。不要因是师父煎的就一口闷。”</p><p>一刻钟后，无心悸，陈玄才将余药喝完。</p><p>“今日做什么？”他问。</p><p>“不握剑。”</p><p>“医棚禁未收剑势一月，普通基础剑可以十日后复验。”</p><p>“所以前十日不握。”李清风把青锋剑连鞘收走，“你的右手昨日连剑都脱过。此时练基础，身体会用左肩和腰替它省力。等伤好再改，比现在停十日更慢。”</p><p>剑峰第一日的课业只有四件事。</p><p>喝药。</p><p>沿峰顶缓步两周，记录哪一步牵动旧伤。</p><p>抄《青元剑诀》第一重。</p><p>午后替李清风把竹篱剩下的裂口补完。</p><p>陈玄抄到第三遍，终于发现外门拓本与剑峰藏本的差别。正文一字不差，每段末尾却多了不同人的小注。有人记凝锋时金火相冲该怎样散气，有人写回云斩若肩先于腰转，十年后会留下何种暗伤。字迹新旧不一，最早一条已经模糊，只剩八字。</p><p>剑出七分，三分归身。</p><p>“三分留作退路？”陈玄问。</p><p>李清风正削替换竹条。他手中小刀锋利，削出的竹子却一边厚一边薄。</p><p>“可以退，也可以出下一剑。”</p><p>“生死时若必须尽力？”</p><p>“尽力不是把所有东西一次扔完。”李清风把削歪的竹条比到缺口，果然不合，只得重来，“除非你身后没有人、前面也没有下一步。否则所谓全力，多半只是没想好后面怎么办。”</p><p>陈玄想起顾长林那场。</p><p>三道青芒交叠后，丹田近空，肩脉逆痛。顾长林若退，他没有第四剑。那不是一式完整杀招，只是把结果押在对方愿不愿意接上。</p><p>“弟子明白。”</p><p>“先别明白。”李清风把第二根仍旧削歪的竹条放下，“把小注逐条抄完，再告诉我哪一条与你有关。”</p><p>傍晚，饭是两碗清汤面。</p><p>面条粗细不一，有些已经软了，有些中间仍硬。盐水煮肉切得也不齐。陈玄吃了两口，没有说“很好”。</p><p>“面煮久了，肉有点老。”</p><p>李清风抬眼：“鲁九教你的？”</p><p>“师父说不要因是师父煎的药便一口闷。饭应当也一样。”</p><p>李清风看着自己碗里黏在一起的两根面，竟点头：“明日你煮。”</p><p>“弟子只会熬药粥。”</p><p>“那便吃药粥。”</p><p>师徒第一顿饭没有谈大比，也没有谈四灵根能走多远。李清风问三号寒髓草近来长势，陈玄说根部透气已经改善，旧裂叶没有剪，因为还能替新叶挡午后温差。</p><p>“鲁九还用那柄缺口药锄？”李清风忽然问。</p><p>“用。木柄换过一截。”</p><p>“他没舍得扔。”</p><p>“师父认识鲁叔很久？”</p><p>李清风夹起一根半生面条：“比认识你久。”</p><p>之后便不说了。</p><p>陈玄也没有追问。</p><p>第二日，东屋桌上仍有一壶冷药。</p><p>第三日也是。</p><p>李清风每日寅时前煎好，放到药性沉稳，再去练剑坪扫叶或修竹篱。陈玄自己验色、分两次喝，随后抄诀、缓步。两人不把关心挂在嘴边，也不把服药当成师徒情深的证明。</p><p>药方有效，伤者按量喝。</p><p>煎药的人记得火候。</p><p>这些已经够重。</p><p>第五日，陈玄在藏本注解里找到与自己最相关的一条：肩有旧伤者，收势不可绕痛，宁停一式，不改中线。</p><p>“我在第十章已经改过偏肩。”他说。</p><p>“你改的是定势。”李清风道，“未收第三段又把肩线改回去了。人受逼迫时，最先回去的往往是自以为已经改掉的旧习。”</p><p>“如何练收？”</p><p>“先不出。”</p><p>第十日复验，右手握力恢复。</p><p>李清风仍没有还青锋剑，只折了一根与剑等长的竹枝。竹枝过轻，不能依靠重量带动收势；稍一用力过猛，枝尖便会颤。</p><p>“只出一剑。”</p><p>陈玄以竹枝走青锋起。</p><p>剑路稳，落点正，收回时却下意识快了半拍。</p><p>“为何急收？”</p><p>“准备第二剑。”</p><p>“第一剑尚未让对手动，第二剑准备给谁？”</p><p>陈玄停住。</p><p>过去六十剑训练，每一剑都有目标。大比里每一招也都要换位置、伤势或灵力。他很少出一剑只为询问对手会如何走。</p><p>李清风捡起另一根枯枝，随手刺向陈玄右肩。</p><p>不快，也没有灵力。</p><p>陈玄向左退半步。</p><p>左侧正是井沿。若还有第二剑，他只能退向竹篱窄角。</p><p>“这一刺没碰到你。”李清风收枝，“赚了什么？”</p><p>“让我自己选了左边。”</p><p>“那便不是没赚。只是它的结果不在剑尖上。”</p><p>“若我不向左？”</p><p>“说明这一剑没有让你觉得左边更安全。”</p><p>陈玄看向脚下。</p><p>一剑可以问路。</p><p>答案由对手的脚给出。</p><p>从那日起，他每日只练三十次空刺。前十次不许碰靶，目标是让李清风摆在地上的木人向某一方向倒；中十次封下一步；最后十次才允许剑尖触物。</p><p>第一日，木人没有一次按预想倒。</p><p>第三日，十次中两次。</p><p>第七日，六次。</p><p>陈玄想加到六十，李清风不许。</p><p>“为什么？”</p><p>“第三十次以后，你的右肩又开始代偿。”</p><p>“弟子没有感觉。”</p><p>“所以我在看。”</p><p>李清风没有说师父会永远替他看。只让他把第三十次与第二十九次分别画下肩线，直到自己能看出那半寸差别。</p><p>一个月后，医棚解除逆势禁练。</p><p>李清风把青锋剑还给他，却仍不许练未收第三段。</p><p>“先把前两段收回来。”</p><p>陈玄按原路出剑。青锋起，回云斩。两道青芒没有被强拉成第三瓣，而是在第二剑结束时沿中线归入丹田。第一次只收回不到一成，余下灵力散在空气里；第十次能收两成；月底稳定在三成。</p><p>剑去七分，三分归身。</p><p>那条旧注直到此刻才从纸上落到经脉里。</p><p>入峰第二个月，陈玄仍是炼气六层后期。</p><p>剑峰聚灵气比药园浓，亲传月例也更足，四属性吸纳速度确实加快。李清风却没有让他立刻服调和丹。三个月损耗测量尚未结束，过早用药会把行气改正与丹药补益混在一起，反而算不清哪一步真正有效。</p><p>损耗不是凭感觉估。</p><p>李清风从资源堂借来四只量灵盏，金、木、水、火各测七日。陈玄每日同一时辰入阵，吸纳一刻钟，再将丹田中对应灵气渡回量盏。吸入多少、留存多少、行过哪处经穴时散得最快，逐项写在册中。</p><p>第一日测火，吸入十份，只留六份半。</p><p>陈玄原以为四灵根驳杂，四气损耗应当相近。七日后，水气能留八份，木气七份半，金气却只有六份。金火相接的曲池穴与肩井旧伤附近，是损耗最大的两处。</p><p>“若直接吃调和丹，会怎样？”他问。</p><p>“四气表面齐了，金火经过旧处仍会散。”李清风把四张记录并在一起，“你会以为丹药有效，因为丹田总量多了；真正需要的药也会被多出来的灵力遮住。”</p><p>第二轮测量前，陈玄调整金火进入次序，又将火气在曲池前停一息。火气留存涨到七份，金气仍只有六份半。李清风这才从亲传份额中换一枚低阶和金丹，不让他整枚吞，而是分成五次，每两日服一份。</p><p>第三轮结束，四气留存差距缩到一份以内。</p><p>资源堂原按四灵根惯例准备每月三枚调和丹。李清风退回两枚，只保留一枚按需分服，剩下份额换成聚灵阵时辰。</p><p>“丹药多留两枚，以后也能用。”陈玄道。</p><p>“能用，不等于现在该拿。”</p><p>“退回去，资源堂会给别人？”</p><p>“会。”</p><p>李清风没有因为剑峰任务库承担额外资源，便把可以领到的都先攥在手里。陈玄也第一次看见，主殿那句“先量，再给”如何落实成二十一天、十二张纸和两枚被退回去的丹药。</p><p>四灵根的慢没有消失。</p><p>只是慢在什么地方，终于不再只是一句笼统判词。</p><p>掌天瓶每月仍凝一滴绿液。</p><p>陈玄只在自己的小药圃催熟低阶药材，种类与年份仍有变化。李清风没有以师父身份搜他的储物袋，也没有问药材为何比寻常长得稳。陈玄同样没有因为被收作亲传便主动交出秘密换信任。</p><p>信任不是把所有能伤到自己的东西摊开。</p><p>是彼此都知道边界在哪里，不趁对方睡着时跨过去。</p><p>第三个月初，宗门下发七宗会武预告。</p><p>会武定在六个月后，青云宗有五个名额。参赛者不满三十岁，境界不得高于筑基初期。各峰先推人，再由宗门统一选拔。</p><p>李清风把预告放到桌上：“想去？”</p><p>“想。”</p><p>“因为血魔子？”</p><p>“一部分。还有六宗的剑、符、体修与阵法。我在宗内看过的路还少。”</p><p>“血魔子已筑基。”</p><p>“弟子知道。”</p><p>“知道不等于见面时还记得。”李清风把冷药壶推过去，“名额不是我给。六个月后自己争。现在先把这壶喝完。”</p><p>陈玄摸了摸壶壁。</p><p>仍是凉的。</p><p>他分两次喝完，没有因六个月后的强敌便多出一剑。</p><p>当夜山风很大。李清风在井边擦无鞘古剑，陈玄在东屋抄最后一页注解。桌上空药壶没有收走，壶底残着一点沉淀后的白色石心乳。</p><p>陈玄洗壶时，李清风隔着窗道：“石心乳别倒井里，埋到竹根外三尺。离根太近会烧须。”</p><p>“师父煎第一壶时倒过？”</p><p>“倒过。死了两根新竹。”</p><p>陈玄把沉淀埋到指定位置，顺手在旁边插一片碎瓦作记。李清风看见，没有夸，只说明年若竹叶发黄，先挖这里查。</p><p>剑峰首座也会煎焦药、削歪竹条，会因为不懂药渣伤根而养死新竹。师父能教他剑，不等于每件事都永远正确；弟子懂药，也不等于该当众替师父遮掩错误。</p><p>第二日，碎瓦仍留在土里。</p><p>没有人拔掉。</p><p>师门不是一句护你一世。</p><p>至少最初的三个月，它只是一条不能带伤乱走的石阶，一根不许加练的竹枝，和每天寅时前已经放凉的一壶药。</p><p>陈玄把空壶洗净，倒扣在桌边。</p><p>明日仍要用。</p><p>（第二十章完）</p>',166)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
